  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])->getSymbol()->getType();
    switch (void)first;;
    switch (token) {
