      if (paren->getSymbol()->getType() == ast::LeftBracket) {
        auto index = make<BinaryExpr>();
        index->op = index->kIndex;
        index->lft = sub;
        i++;
        if (i < children.size())
          index->rht = self(dynamic_cast<ast::ExpressionContext*>(children[i]));
        i++; // Skip RightBracket
        sub = index;
        continue;
      }
    }
  }
  return sub;
}

